func payAppStatusBadge(s models.PaymentApplicationStatus) string {
	const base = "inline-block rounded px-2 py-0.5 text-small font-medium "
	switch s {
	case models.PaymentApplicationStatusActive:
		return base + "bg-success-soft text-success-hover border border-success-border"
	case models.PaymentApplicationStatusReversed:
		return base + "bg-background text-text-muted border border-border"
	default:
		return base + "bg-background text-text-muted border border-border"
	}
}

func receiptDateVal(rcpt models.CustomerReceipt) string {
	if rcpt.ReceiptDate.IsZero() {
		return ""
	}
	return rcpt.ReceiptDate.Format("2006-01-02")
}

